const rows = $input.all().map(item => item.json);

const prochaine = rows.find(r => (r.status || '').trim().toLowerCase() === 'à publier');

if (!prochaine) {
  throw new Error("Aucun sujet avec le statut 'à publier' dans le calendrier éditorial. Ajoute des lignes dans le Google Sheet.");
}

return [{
  json: {
    sujet: prochaine.theme,
    row_id: prochaine.id,
    row_number: prochaine.row_number
  }
}];

const raw = $input.first().json.choices[0].message.content;

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
}

function toBoldUnicode(str) {
  const boldMap = {
    a:'𝗮',b:'𝗯',c:'𝗰',d:'𝗱',e:'𝗲',f:'𝗳',g:'𝗴',h:'𝗵',i:'𝗶',j:'𝗷',k:'𝗸',l:'𝗹',m:'𝗺',
    n:'𝗻',o:'𝗼',p:'𝗽',q:'𝗾',r:'𝗿',s:'𝘀',t:'𝘁',u:'𝘂',v:'𝘃',w:'𝘄',x:'𝘅',y:'𝘆',z:'𝘇',
    A:'𝗔',B:'𝗕',C:'𝗖',D:'𝗗',E:'𝗘',F:'𝗙',G:'𝗚',H:'𝗛',I:'𝗜',J:'𝗝',K:'𝗞',L:'𝗟',M:'𝗠',
    N:'𝗡',O:'𝗢',P:'𝗣',Q:'𝗤',R:'𝗥',S:'𝗦',T:'𝗧',U:'𝗨',V:'𝗩',W:'𝗪',X:'𝗫',Y:'𝗬',Z:'𝗭',
    '0':'𝟬','1':'𝟭','2':'𝟮','3':'𝟯','4':'𝟰','5':'𝟱','6':'𝟲','7':'𝟳','8':'𝟴','9':'𝟵'
  };
  return str.split('').map(ch => boldMap[ch] || ch).join('');
}

let text = parsed.post || '';
text = text.replace(/\*\*(.+?)\*\*/g, (_, inner) => toBoldUnicode(inner));
text = text.replace(/^-\s+/gm, '• ');

const sujetNode = $('Choisir le prochain sujet').first().json;

return [{
  json: {
    texte_formate: text,
    longueur: text.length,
    image_prompt: parsed.image_prompt || '',
    image_keywords: parsed.image_keywords || '',
    row_id: sujetNode.row_id,
    sujet: sujetNode.sujet
  }
}];

const unsplashResult = $input.first();
const formatterData = $('Formater le texte (unicode + puces)').first().json;

// Vérifie si Unsplash a retourné une image valide
const hasImage = unsplashResult.json && unsplashResult.json.urls && unsplashResult.json.urls.regular;

return [{
  json: {
    texte_formate: formatterData.texte_formate,
    image_prompt: formatterData.image_prompt,
    image_keywords: formatterData.image_keywords,
    row_id: formatterData.row_id,
    sujet: formatterData.sujet,
    unsplash_url: hasImage ? unsplashResult.json.urls.regular : null,
    use_pollinations: !hasImage
  }
}];
